interface RadarChartProps {
  skills: Skill[];
  isVisible: boolean;
}

function RadarChart({ skills, isVisible }: RadarChartProps) {
  const points = skills.map((skill, index) => {
    const angle = (index / skills.length) * 2 * Math.PI;
    const radius = (skill.level / 100) * 140; // Scale to 140px max radius
    const x = Math.cos(angle) * radius + 160;
    const y = Math.sin(angle) * radius + 160;
    return `${x},${y}`;
  }).join(' ');

  // Note: centerPoints is computed for potential future use in radar chart centering

  return (
    <div className="relative">
      <svg width="320" height="320" className="w-full h-auto">
        {/* Background grid */}
        <defs>
          <linearGradient id="skillGradient" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#00D1FF" />
            <stop offset="100%" stopColor="#7F52FF" />
          </linearGradient>
        </defs>

        {/* Outer circle */}
        <circle
          cx="160"
          cy="160"
          r="140"
          fill="none"
          stroke="rgba(255, 255, 255, 0.1)"
          strokeWidth="1"
        />

        {/* Inner circles */}
        {[0.25, 0.5, 0.75, 1.0].map((scale, index) => (
          <circle
            key={index}
            cx="160"
            cy="160"
            r={140 * scale}
            fill="none"
            stroke="rgba(255, 255, 255, 0.05)"
            strokeWidth="1"
          />
        ))}

        {/* Skill lines */}
            {skills.map((_, index) => {
            const angle = (index / skills.length) * 2 * Math.PI;
          const x = Math.cos(angle) * 140 + 160;
          const y = Math.sin(angle) * 140 + 160;

          return (
            <line
              key={index}
              x1="160"
              y1="160"
              x2={x}
              y2={y}
              stroke="rgba(255, 255, 255, 0.1)"
              strokeWidth="1"
            />
          );
        })}

        {/* Animated skill area */}
        <motion.polygon
          points={points}
          fill="url(#skillGradient)"
          opacity={isVisible ? 0.3 : 0}
          initial={{ scale: 0 }}
          animate={{ scale: isVisible ? 1 : 0 }}
          transition={{ duration: 1.5, ease: "easeOut" }}
          stroke="url(#skillGradient)"
          strokeWidth="2"
        />

        {/* Center highlight */}
        <motion.circle
          cx="160"
          cy="160"
          r="8"
          fill="white"
          opacity={isVisible ? 1 : 0}
          initial={{ scale: 0 }}
          animate={{ scale: isVisible ? 1 : 0 }}
          transition={{ duration: 0.5 }}
        />

        {/* Floating particles */}
        {isVisible && (
          <>
            {skills.map((_, index) => (
              <motion.circle
                key={index}
                cx="160"
                cy="160"
                r="2"
                fill="white"
                opacity="0.5"
                initial={{ scale: 0, opacity: 0 }}
                animate={{
                  scale: [0, 1, 0],
                  opacity: [0, 0.5, 0],
                  x: [0, Math.random() * 100 - 50, 0],
                  y: [0, Math.random() * 100 - 50, 0],
                }}
                transition={{
                  duration: 2,
                  delay: index * 0.2,
                  repeat: Infinity,
                  repeatDelay: 3,
                }}
              />
            ))}
          </>
        )}
      </svg>

      {/* Category name overlay */}
      <div className="absolute top-4 left-4 right-4 text-center">
        <h4 className="text-lg font-bold text-text-heading">
          {skills[0]?.name.split(' ')[0] || 'Skills'}
        </h4>
      </div>
    </div>
  );
}

